import React, { useEffect, useState } from "react";

function booking() {
  const [bookings, setBookings] = useState([]);
  const [form, setForm] = useState({
    PhongSo: "",
    MaKH: "",
    NgayDat: "",
    NgayNhan: "",
    NgayTra: "",
    SoNguoi: "",
    TinhTrang: "dadat",
  });
  const [editMode, setEditMode] = useState(false);

  // ----------- Lấy tất cả booking (sắp xếp theo số phòng tăng dần) -----------
  const fetchAllBookings = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/booking/allbooking");
      const data = await res.json();

      // Sắp xếp theo PhongSo tăng dần
      const sorted = data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setBookings(sorted);
    } catch {
      alert("Lỗi khi tải danh sách booking");
    }
  };

  useEffect(() => {
    fetchAllBookings();
  }, []);

  // ----------- Nhập form -----------
  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  // ----------- Thêm booking -----------
  const handleAddBooking = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/booking/addbooking", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      alert(res.ok ? data.message : data.error);
      if (res.ok) {
        setForm({ PhongSo: "", MaKH: "", NgayDat: "", NgayNhan: "", NgayTra: "", SoNguoi: "", TinhTrang: "dadat" });
        fetchAllBookings();
      }
    } catch {
      alert("Lỗi khi thêm booking");
    }
  };

  // ----------- Cập nhật booking -----------
  const handleUpdateBooking = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/booking/updatebooking", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      alert(res.ok ? data.message : data.error);
      if (res.ok) {
        setEditMode(false);
        setForm({ PhongSo: "", MaKH: "", NgayDat: "", NgayNhan: "", NgayTra: "", SoNguoi: "", TinhTrang: "dadat" });
        fetchAllBookings();
      }
    } catch {
      alert("Lỗi khi cập nhật booking");
    }
  };

  // ----------- Hủy booking -----------
  const handleDeleteBooking = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/booking/deletebooking", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ PhongSo: form.PhongSo, NgayDat: form.NgayDat }),
      });
      const data = await res.json();
      alert(res.ok ? data.message : data.error);
      if (res.ok) {
        setEditMode(false);
        setForm({ PhongSo: "", MaKH: "", NgayDat: "", NgayNhan: "", NgayTra: "", SoNguoi: "", TinhTrang: "dadat" });
        fetchAllBookings();
      }
    } catch {
      alert("Lỗi khi hủy booking");
    }
  };

  // ----------- Xem trạng thái booking theo phòng -----------
  const handleCheckStatus = async () => {
    try {
      const params = new URLSearchParams({ PhongSo: form.PhongSo, MaKH: form.MaKH, NgayDat: form.NgayDat });
      const res = await fetch(`http://localhost:5000/api/booking/statusbooking?${params.toString()}`);
      const data = await res.json();
      if (res.ok) {
        setForm(data);
        setEditMode(true);
      } else {
        alert(data.error);
      }
    } catch {
      alert("Lỗi khi xem trạng thái");
    }
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Quản lý đặt phòng</h1>

      {/* Form thêm / sửa booking */}
      <div className="mb-6 p-4 border rounded shadow">
        <h2 className="font-semibold mb-2">{editMode ? "Cập nhật booking" : "Thêm booking mới"}</h2>
        <div className="grid grid-cols-3 gap-3">
          {["PhongSo", "MaKH", "NgayDat", "NgayNhan", "NgayTra", "SoNguoi"].map((f) => (
            <input
              key={f}
              type={f.includes("Ngay") ? "date" : "text"}
              name={f}
              placeholder={f}
              value={form[f]}
              onChange={handleChange}
              className="border p-2 rounded"
              disabled={editMode && f === "PhongSo"}
            />
          ))}
          <select name="TinhTrang" value={form.TinhTrang} onChange={handleChange} className="border p-2 rounded">
            <option value="trong">Trống</option>
            <option value="dadat">Đã đặt</option>
          </select>
        </div>

        <div className="mt-3 space-x-2">
          {editMode ? (
            <>
              <button onClick={handleUpdateBooking} className="bg-green-500 text-white px-4 py-2 rounded">Cập nhật</button>
              <button onClick={handleDeleteBooking} className="bg-red-500 text-white px-4 py-2 rounded">Hủy</button>
              <button onClick={() => { setEditMode(false); setForm({ PhongSo: "", MaKH: "", NgayDat: "", NgayNhan: "", NgayTra: "", SoNguoi: "", TinhTrang: "dadat" }); }} className="bg-gray-400 text-white px-4 py-2 rounded">Hủy edit</button>
            </>
          ) : (
            <>
              <button onClick={handleAddBooking} className="bg-blue-500 text-white px-4 py-2 rounded">Thêm</button>
              <button onClick={handleCheckStatus} className="bg-indigo-500 text-white px-4 py-2 rounded">Xem trạng thái</button>
            </>
          )}
        </div>
      </div>

      {/* Table tất cả booking */}
      <table className="w-full border-collapse border">
        <thead>
          <tr className="bg-gray-200">
            <th className="border p-2">Phòng số</th>
            <th className="border p-2">Mã KH</th>
            <th className="border p-2">Ngày đặt</th>
            <th className="border p-2">Ngày nhận</th>
            <th className="border p-2">Ngày trả</th>
            <th className="border p-2">Số người</th>
            <th className="border p-2">Tình trạng</th>
            <th className="border p-2">Hành động</th>
          </tr>
        </thead>
        <tbody>
          {bookings.map((b) => (
            <tr key={`${b.PhongSo}-${b.NgayDat}`} className="hover:bg-gray-100 cursor-pointer" onClick={() => { setForm(b); setEditMode(true); }}>
              <td className="border p-2">{b.PhongSo}</td>
              <td className="border p-2">{b.MaKH}</td>
              <td className="border p-2">{b.NgayDat}</td>
              <td className="border p-2">{b.NgayNhan}</td>
              <td className="border p-2">{b.NgayTra}</td>
              <td className="border p-2">{b.SoNguoi}</td>
              <td className="border p-2">{b.TinhTrang}</td>
              <td className="border p-2 space-x-1 text-center">
                <button onClick={() => { setForm(b); setEditMode(true); }} className="bg-yellow-500 text-white px-2 py-1 rounded">Sửa</button>
                <button onClick={() => { setForm(b); handleDeleteBooking(); }} className="bg-red-500 text-white px-2 py-1 rounded">Hủy</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default booking;
